{
    "level": "A1–A2",
    "intro": "In this topic you learn <strong>possessive adjectives and possessive pronouns</strong> - two forms for expressing belonging.",
    "rules": [
        {
            "label": "Adjectives",
            "color": "emerald",
            "text": "<strong>Possessive adjectives</strong> - before a noun:",
            "example": "This is my book. Her name is Maria."
        },
        {
            "label": "Pronouns",
            "color": "blue",
            "text": "<strong>Possessive pronouns</strong> — instead of a noun:",
            "example": "This book is mine. The blue bag is hers."
        },
        {
            "label": "Key Rule",
            "color": "amber",
            "text": "<strong>Rule:</strong> adjective + noun, pronoun instead of noun",
            "example": "my car (adj+noun) → The car is mine (pronoun)"
        }
    ]
}

{
    "title": "1. Two possessive forms",
    "intro": "To express belonging (whose is it?) the English language has two forms:",
    "items": [
        {
            "label": "Adjectives",
            "title": "Possessive adjectives",
            "subtitle": "my, your, his, her, its, our, their — stand BEFORE by a noun"
        },
        {
            "label": "Pronouns",
            "title": "Possessive pronouns",
            "subtitle": "mine, yours, his, hers, ours, theirs — stand INSTEAD of a noun"
        }
    ]
}

{
    "title": "2. Complete table of possessive forms",
    "intro": "Comparison of all possessive adjectives and possessive pronouns:",
    "rows": [
        {
            "en": "my",
            "ua": "my/my/mine (+ noun)",
            "note": "mine - mine (independent)"
        },
        {
            "en": "your",
            "ua": "yours (+ noun)",
            "note": "yours - yours (independent)"
        },
        {
            "en": "his[[[CODX_5]]]his (+ noun)[[CODX_6]]]his his (independently)",
            "ua": "його (+ noun)",
            "note": "his — його (самостійно)"
        },
        {
            "en": "her",
            "ua": "her (+ noun)",
            "note": "hers - hers (independently)"
        },
        {
            "en": "its",
            "ua": "his/her for animals/objects",
            "note": " has NO form pronoun!"
        },
        {
            "en": "our",
            "ua": "our (+ noun)",
            "note": "ours - our (independent)"
        },
        {
            "en": "their",
            "ua": "their (+ noun)",
            "note": "theirs (independently)"
        }
    ],
    "warning": "📌 His has the same form for adjective and pronoun. Its does NOT have a pronoun form!"
}

{
    "title": "3. Possessive Adjectives - Possessive adjectives",
    "sections": [
        {
            "label": "What are possessive adjectives?",
            "color": "emerald",
            "description": "Possessive adjectives <strong>always come before a noun</strong> and show who owns something. They can NOT stand on their own.",
            "examples": [
                {
                    "en": "This is my book.",
                    "ua": "This is my book."
                },
                {
                    "en": "Your car is new.",
                    "ua": "Your car is new."
                },
                {
                    "en": "His name is John.",
                    "ua": "His name John."
                },
                {
                    "en": "Her sister lives here.",
                    "ua": "Her sister lives here."
                },
                {
                    "en": "The dog wagged its tail.",
                    "ua": "The dog wagged its tail."
                },
                {
                    "en": "Our house is big.",
                    "ua": "Our house big."
                },
                {
                    "en": "Their children are at school.",
                    "ua": "Their children are at school."
                }
            ]
        },
        {
            "label": "Always before a noun",
            "color": "sky",
            "description": "Possessive adjectives <strong>never stand alone</strong> — they are always followed by a noun.",
            "examples": [
                {
                    "en": "my friend (✓)",
                    "ua": "my friend"
                },
                {
                    "en": "This is my. (✗)",
                    "ua": "ERROR - no noun!"
                },
                {
                    "en": "her idea (✓)",
                    "ua": "her idea"
                },
                {
                    "en": "The idea is her. (✗)",
                    "ua": "ERROR - the pronoun hers is required!"
                }
            ],
            "note": "📌 Adjective always + noun. Does not work without a noun!"
        },
        {
            "label": "My, your, his, her, its, our, their",
            "color": "purple",
            "description": "All seven possessive adjectives are used in the same way - before a noun.",
            "examples": [
                {
                    "en": "my pen, your bag, his phone",
                    "ua": "my pen, your bag, his phone"
                },
                {
                    "en": "her laptop, its color, our plan",
                    "ua": "her laptop, its color, our plan"
                },
                {
                    "en": "their house",
                    "ua": "their house"
                }
            ]
        },
        {
            "label": "Its vs It's - don't confuse!",
            "color": "amber",
            "description": "<strong>Its</strong> (without apostrophe) is a possessive adjective. <strong>It's</strong> (with an apostrophe) is short for it is.",
            "examples": [
                {
                    "en": "The cat ate its food. (possessive)",
                    "ua": "The cat ate his food."
                },
                {
                    "en": "It's raining. (it is)",
                    "ua": "It is raining."
                },
                {
                    "en": "The city and its people. (possessive)",
                    "ua": "The city and its people."
                },
                {
                    "en": "It's a beautiful day. (it is)",
                    "ua": "Good day."
                }
            ],
            "note": "📌 Its = possessive (whose). It's = it is (it is)."
        }
    ]
}

{
    "title": "4. Possessive Pronouns — Possessive pronouns",
    "sections": [
        {
            "label": "What are possessive pronouns?",
            "color": "blue",
            "description": "Possessive pronouns <strong>replace a noun</strong> and show ownership. They stand alone, WITHOUT a noun after them.",
            "examples": [
                {
                    "en": "This book is mine.",
                    "ua": "This book is mine."
                },
                {
                    "en": "The car is yours.",
                    "ua": "Машина твой."
                },
                {
                    "en": "That pen is his.",
                    "ua": "That pen his."
                },
                {
                    "en": "The blue bag is hers.",
                    "ua": "The blue bag is hers."
                },
                {
                    "en": "The house is ours.",
                    "ua": "House is ours."
                },
                {
                    "en": "Those keys are theirs.",
                    "ua": "Those keys theirs."
                }
            ]
        },
        {
            "label": "Stand alone",
            "color": "sky",
            "description": "Possessive pronouns <strong>do not need a noun</strong> after them - they themselves are a substitute for a noun.",
            "examples": [
                {
                    "en": "This is mine. (✓)",
                    "ua": "This is mine."
                },
                {
                    "en": "This is mine book. (✗)",
                    "ua": "ERROR - redundant noun!"
                },
                {
                    "en": "That's hers. (✓)",
                    "ua": "That's hers."
                },
                {
                    "en": "That's hers bag. (✗)",
                    "ua": "ERROR - cannot be used with a noun!"
                }
            ],
            "note": "📌 Pronoun instead of noun. Never add a noun after!"
        },
        {
            "label": "Mine, yours, his, hers, ours, theirs",
            "color": "purple",
            "description": "Six possessive pronouns (its does not have this form!).",
            "examples": [
                {
                    "en": "Is this pen yours? — Yes, it's mine.",
                    "ua": "Is this your pen? — Yes, mine."
                },
                {
                    "en": "His car is red, hers is blue.",
                    "ua": "His car is red, hers is blue."
                },
                {
                    "en": "Our office is big, theirs is small.",
                    "ua": "Our office is big, theirs is small."
                }
            ]
        },
        {
            "label": "His is a special case of",
            "color": "amber",
            "description": "<strong>His</strong> has the same form as a possessive adjective and as a possessive pronoun.",
            "examples": [
                {
                    "en": "his book (adjective)",
                    "ua": "his book"
                },
                {
                    "en": "This book is his. (pronoun)",
                    "ua": "This book is his."
                }
            ],
            "note": "📌 His is the only word that works both ways!"
        }
    ]
}

{
    "title": "5. How to choose: Adjective or Pronoun?",
    "sections": [
        {
            "label": "Rule 1: Is there a noun after?",
            "color": "emerald",
            "description": "If the possessive form is followed by <strong>noun</strong>, use <strong>adjective</strong>.",
            "examples": [
                {
                    "en": "This is my car.",
                    "ua": "This is my car. (is a noun "car")"
                },
                {
                    "en": "Her sister is tall.",
                    "ua": "Her sister is tall. (is a noun "sister")"
                },
                {
                    "en": "Their house is beautiful.",
                    "ua": "Their house is beautiful. (there is a noun "house")"
                }
            ]
        },
        {
            "label": "Rule 2: Has the noun already been mentioned?",
            "color": "blue",
            "description": "If the noun is already known and you don't want to repeat it, use <strong>pronoun</strong>.",
            "examples": [
                {
                    "en": "My car is red. Yours is blue.",
                    "ua": "My car is red. Your blue (car not repeated)"
                },
                {
                    "en": "Her bag is big. Mine is small.",
                    "ua": "Her bag is big. My little one. (bag not repeated)"
                },
                {
                    "en": "Their office is new. Ours is old.",
                    "ua": "Their office is new. Our old man."
                }
            ]
        },
        {
            "label": "Rule 3: The question "Whose?" — It's mine.",
            "color": "purple",
            "description": "У відповіді на питання <strong>Whose?</strong> (Чий?) часто використовуємо pronoun.",
            "examples": [
                {
                    "en": "Whose book is this? — It's mine.",
                    "ua": "Whose book is this? - Mine."
                },
                {
                    "en": "Whose keys are these? — They're hers.",
                    "ua": "Whose keys are these? — Hers."
                },
                {
                    "en": "Whose car is that? — It's theirs.",
                    "ua": "Whose car is that? — Theirs."
                }
            ],
            "note": "📌 In the answer: mine/yours/his/hers/ours/theirs (pronouns)."
        }
    ]
}

{
    "title": "6. Comparison of forms",
    "sections": [
        {
            "label": "My vs Mine",
            "color": "emerald",
            "description": "<strong>My</strong> + noun. <strong>Mine</strong> instead of noun.",
            "examples": [
                {
                    "en": "This is my book.",
                    "ua": "This is my book. (my + book)"
                },
                {
                    "en": "This book is mine.",
                    "ua": "This book is mine. (mine instead of book)"
                },
                {
                    "en": "My phone is new.",
                    "ua": "My phone is new."
                },
                {
                    "en": "The new phone is mine.",
                    "ua": "My new phone."
                }
            ]
        },
        {
            "label": "Your vs Yours",
            "color": "sky",
            "description": "<strong>Your</strong> + noun. <strong>Yours</strong> instead of a noun.",
            "examples": [
                {
                    "en": "Is this your car?",
                    "ua": "Is this your car? (your + car)"
                },
                {
                    "en": "Is this car yours?",
                    "ua": "Is this car yours? (yours instead of car)"
                },
                {
                    "en": "Your idea is great.",
                    "ua": "Your idea is great."
                },
                {
                    "en": "The idea is yours.",
                    "ua": "Your idea."
                }
            ]
        },
        {
            "label": "Her vs Hers",
            "color": "purple",
            "description": "<strong>Her</strong> + noun. <strong>Hers</strong> instead of a noun.",
            "examples": [
                {
                    "en": "Her bag is blue.",
                    "ua": "Her bag is blue. (her + bag)"
                },
                {
                    "en": "The blue bag is hers.",
                    "ua": "The blue bag is hers. (hers instead of bag)"
                },
                {
                    "en": "Her answer is correct.",
                    "ua": "Her answer is correct."
                },
                {
                    "en": "The correct answer is hers.",
                    "ua": "The correct answer is hers."
                }
            ]
        },
        {
            "label": "Our vs Ours, Their vs Theirs",
            "color": "amber",
            "description": "The same principle for our/ours and their/theirs.",
            "examples": [
                {
                    "en": "Our house vs The house is ours",
                    "ua": "Наш будинок vs Будинок наш"
                },
                {
                    "en": "Their dog vs The dog is theirs",
                    "ua": "Їхня собака vs Собака їхня"
                }
            ],
            "note": "📌 Adjective + noun. Pronoun замість noun."
        }
    ]
}

{
    "title": "7. Typical mistakes of Ukrainian speakers",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Pronoun + noun (extra noun).",
            "wrong": "This is mine book. / That's her car.",
            "right": " ✅ <span class="font-mono">This is my book. / That's her car.</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Adjective without noun.",
            "wrong": "This book is my. / The car is her.",
            "right": "​​​​ <span class="font-mono">This book is mine. / The car is hers.</span>"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Confusion of its and it's.",
            "wrong": "Its raining. / The dog wagged its tail.",
            "right": " ✅ <span class="font-mono">It's raining. / The dog wagged its tail.</span>"
        },
        {
            "label": "Error 4",
            "color": "purple",
            "title": "Incorrect form (mines, hers book).",
            "wrong": "This is mines. / That's her bag.",
            "right": " ✅ <span class="font-mono">This is mine. / That's her bag.</span>"
        }
    ]
}

{
    "title": "9. Practice",
    "select_title": "Exercise 1. Choose the correct form",
    "select_intro": "Fill in the blanks with the correct possessive form (adjective or pronoun).",
    "selects": [
        {
            "label": "This is ___ book. (my / mine)",
            "prompt": "What form?"
        },
        {
            "label": "This book is ___. (my / mine)",
            "prompt": "What shape?"
        },
        {
            "label": "___ car is red. (Her / Hers)",
            "prompt": "What shape?"
        },
        {
            "label": "The red car is ___. (her / hers)",
            "prompt": "What shape?"
        },
        {
            "label": "Is this pen ___? (your / yours)",
            "prompt": "Which one form?"
        }
    ],
    "options": [
        "my",
        "mine",
        "your",
        "yours",
        "his",
        "her ",
        "hers",
        "our",
        "ours",
        "their",
        "theirs"
    ],
    "input_title": "Exercise 2. Fill in the blanks",
    "input_intro": "Write the correct possessive form.",
    "inputs": [
        {
            "before": "This is ___ phone. (my phone)",
            "after": "→"
        },
        {
            "before": "This phone is ___. (my)",
            "after": "→"
        },
        {
            "before": "___ house is big. (our house)",
            "after": "→"
        },
        {
            "before": "The house is ___. (our)",
            "after": "→"
        }
    ],
    "rephrase_title": "Exercise 3. Error correction",
    "rephrase_intro": "Find and correct the error with possessive forms.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "This is mine book.",
            "example_target": "This is my book."
        },
        {
            "original": "1. This book is my.",
            "placeholder": "Fix the error"
        },
        {
            "original": "2. That is hers car.",
            "placeholder": "Fix the error"
        },
        {
            "original": "3. It's a beautiful day. — my / mine, your / yours",
            "placeholder": "Виправ помилку"
        }
    ]
}

